#include <stdio.h>
#include <limits.h>
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y, Z, A, B, C;
        scanf("%d %d %d %d %d %d", &X, &Y, &Z, &A, &B, &C);
        int dp[X + 1][Y + 1][Z + 1];
        for (int i = 0; i <= X; i++) {
            for (int j = 0; j <= Y; j++) {
                for (int k = 0; k <= Z; k++) {
                    if (i == 0 && j == 0 && k == 0) {
                        dp[i][j][k] = 0;
                    } else {
                        dp[i][j][k] = INT_MAX;
                        if (i > 0) dp[i][j][k] = min(dp[i][j][k], dp[i - 1][j][k] + A);
                        if (j > 0) dp[i][j][k] = min(dp[i][j][k], dp[i][j - 1][k] + A);
                        if (k > 0) dp[i][j][k] = min(dp[i][j][k], dp[i][j][k - 1] + A);
                        if (i > 0 && j > 0) dp[i][j][k] = min(dp[i][j][k], dp[i - 1][j - 1][k] + B);
                        if (i > 0 && k > 0) dp[i][j][k] = min(dp[i][j][k], dp[i - 1][j][k - 1] + B);
                        if (j > 0 && k > 0) dp[i][j][k] = min(dp[i][j][k], dp[i][j - 1][k - 1] + B);
                        if (i > 0 && j > 0 && k > 0) dp[i][j][k] = min(dp[i][j][k], dp[i - 1][j - 1][k - 1] + C);
                    }
                }
            }
        }
        printf("%d\n", dp[X][Y][Z]);
    }
    return 0;
}

