import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt();
            int Y = sc.nextInt();
            int Z = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            int C = sc.nextInt();
            int[][][] dp = new int[X + 1][Y + 1][Z + 1];
            for (int i = 0; i <= X; i++) {
                for (int j = 0; j <= Y; j++) {
                    for (int k = 0; k <= Z; k++) {
                        if (i == 0 && j == 0 && k == 0) {
                            dp[i][j][k] = 0;
                        } else {
                            dp[i][j][k] = Integer.MAX_VALUE;
                            if (i > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i - 1][j][k] + A);
                            if (j > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i][j - 1][k] + A);
                            if (k > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i][j][k - 1] + A);
                            if (i > 0 && j > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i - 1][j - 1][k] + B);
                            if (i > 0 && k > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i - 1][j][k - 1] + B);
                            if (j > 0 && k > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i][j - 1][k - 1] + B);
                            if (i > 0 && j > 0 && k > 0) dp[i][j][k] = Math.min(dp[i][j][k], dp[i - 1][j - 1][k - 1] + C);
                        }
                    }
                }
            }
            System.out.println(dp[X][Y][Z]);
        }
    }
}

