for (let i = 0; i < T; i++) {
    const [X, Y, Z, A, B, C] = readline().split(' ').map(Number);
    const dp = Array(X + 1).fill().map(() => Array(Y + 1).fill().map(() => Array(Z + 1).fill(Infinity)));
    dp[0][0][0] = 0;
    for (let x = 0; x <= X; x++) {
        for (let y = 0; y <= Y; y++) {
            for (let z = 0; z <= Z; z++) {
                if (x > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x - 1][y][z] + A);
                if (y > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x][y - 1][z] + A);
                if (z > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x][y][z - 1] + A);
                if (x > 0 && y > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x - 1][y - 1][z] + B);
                if (x > 0 && z > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x - 1][y][z - 1] + B);
                if (y > 0 && z > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x][y - 1][z - 1] + B);
                if (x > 0 && y > 0 && z > 0) dp[x][y][z] = Math.min(dp[x][y][z], dp[x - 1][y - 1][z - 1] + C);
            }
        }
    }
    console.log(dp[X][Y][Z]);
}
